query.sparql:
SELECT DISTINCT ?answer WHERE {
  ?answer wdt:P31 wd:Q16521. # Animals
  ?operation wdt:P710 wd:Q625657. # Australian Defence Force involved in the operation
  ?operation wdt:P710 ?answer. # Animal involved in the operation
}

SELECT ?answer WHERE {
  ?answer wdt:P451 wd:Q4463198;  # Unmarried partner: Triss Merigold
          wdt:P451 wd:Q4205826.  # Unmarried partner: Yennefer of Vengerberg
}

SELECT ?answer WHERE {
  wd:Q860580 wdt:P112 ?founder. # Tencent's founders
  ?founder wdt:P102 ?party. # Member of political party
  ?party wdt:P31 wd:Q19211. # Instance of National People's Congress
  BIND(?founder AS ?answer)
}

SELECT ?answer WHERE {
  wd:Q550311 wdt:P50 ?answer.
  ?answer wdt:P921 ?subject.
  ?subject rdfs:label "middle school student"@en.
}
